css:
@import url("_global_style.css");

.card { text-align: center; font-size: 18px; }

/* OCCLUSION CSS START - don't edit this */
#io-overlay {
  position:absolute;
  top:0;
  width:100%;
  z-index:3
}

#io-original {
  position:relative;
  top:0;
  width: 100%;
  z-index:2;
  visibility: hidden;
}

#io-wrapper {
  position:relative;
  width: 100%;
}
/* OCCLUSION CSS END */

#io-header { font-size: 1.1em; margin-bottom: 0.5em; font-weight: 600; }
#io-footer { max-width: 80%; margin: 0.8em auto 0; font-style: italic; opacity: 0.9; }
#io-extra-wrapper { width: 80%; margin: 0.8em auto 0; }
#io-extra { text-align: center; display: inline-block; }
.io-extra-entry {
  margin-top: 0.8em;
  font-size: 0.9em;
  text-align: left;
  padding: 12px 16px;
  border-radius: 8px;
  background: rgba(255, 255, 255, 0.65);
}
.nightMode .io-extra-entry { background: rgba(42, 43, 54, 0.65); }
.io-field-descr { margin-bottom: 0.2em; font-weight: bold; }
#io-revl-btn {
  font-size: 0.75em;
  padding: 8px 16px;
  border-radius: 8px;
  border: 1px solid #dcdde1;
  background: #fff;
  cursor: pointer;
  margin-top: 0.5em;
}
.nightMode #io-revl-btn { background: #2a2b36; border-color: #4a4b56; color: #f5f6fa; }
.mobile .card, .mobile #content { font-size: 16px; margin: 0; }
.mobile #io-extra-wrapper { width: 95%; }
.mobile #io-revl-btn { font-size: 0.85em; }

IO Card.Front:
{{#Image}}
<div id="io-header">{{Header}}</div>
<div id="io-wrapper">
  <div id="io-overlay">{{Question Mask}}</div>
  <div id="io-original">{{Image}}</div>
</div>
<div id="io-footer">{{Footer}}</div>

<script>
// Prevent original image from loading before mask
aFade = 50, qFade = 0;
var mask = document.querySelector('#io-overlay>img');
function loaded() {
    var original = document.querySelector('#io-original');
    original.style.visibility = "visible";
}
if (mask === null || mask.complete) {
    loaded();
} else {
    mask.addEventListener('load', loaded);
}
</script>
{{/Image}}

IO Card.Back:
{{#Image}}
<div id="io-header">{{Header}}</div>
<div id="io-wrapper">
  <div id="io-overlay">{{Answer Mask}}</div>
  <div id="io-original">{{Image}}</div>
</div>
{{#Footer}}<div id="io-footer">{{Footer}}</div>{{/Footer}}
<button id="io-revl-btn" onclick="toggle();">Toggle Masks</button>
<div id="io-extra-wrapper">
  <div id="io-extra">
    {{#Remarks}}
      <div class="io-extra-entry">
        <div class="io-field-descr">Remarks</div>{{Remarks}}
      </div>
    {{/Remarks}}
    {{#Sources}}
      <div class="io-extra-entry">
        <div class="io-field-descr">Sources</div>{{Sources}}
      </div>
    {{/Sources}}
    {{#Extra 1}}
      <div class="io-extra-entry">
        <div class="io-field-descr">Extra 1</div>{{Extra 1}}
      </div>
    {{/Extra 1}}
    {{#Extra 2}}
      <div class="io-extra-entry">
        <div class="io-field-descr">Extra 2</div>{{Extra 2}}
      </div>
    {{/Extra 2}}
  </div>
</div>

<script>
// Toggle answer mask on clicking the image
var toggle = function() {
  var amask = document.getElementById('io-overlay');
  if (amask.style.display === 'block' || amask.style.display === '')
    amask.style.display = 'none';
  else
    amask.style.display = 'block'
}

// Prevent original image from loading before mask
aFade = 50, qFade = 0;
var mask = document.querySelector('#io-overlay>img');
function loaded() {
    var original = document.querySelector('#io-original');
    original.style.visibility = "visible";
}
if (mask === null || mask.complete) {
    loaded();
} else {
    mask.addEventListener('load', loaded);
}
</script>
{{/Image}}
